   SSPDR        : aliased SSPDR_Register;
   SSPSR        : aliased SSPSR_Register;
   SSPCPSR      : aliased SSPCPSR_Register;
   SSPIMSC      : aliased SSPIMSC_Register;
   SSPRIS       : aliased SSPRIS_Register;
   SSPMIS       : aliased SSPMIS_Register;
