   SSPPERIPHID1 : aliased SSPPERIPHID1_Register;
   SSPPERIPHID2 : aliased SSPPERIPHID2_Register;
   SSPPERIPHID3 : aliased SSPPERIPHID3_Register;
   SSPPCELLID0  : aliased SSPPCELLID0_Register;
